  let current = null;

  for (const line of lines) {
    if (/^\s*\* /.test(line)) {
      if (current) blocks.push(current);
      current = [line];
      continue;
    }
    if (current) {
      if (/^- [^\s]/.test(line)) {
        blocks.push(current);
        current = null;
      } else {
        current.push(line);
      }
    }
