  const blocks = [];
  let currentTop = null;

  for (const line of lines) {
    if (!/^\s*[-*] /.test(line)) continue;
    const indent = bulletIndent(line);
    if (indent === 0) {
      currentTop = { title: line.replace(/^\s*[-*]\s+/, '').trim(), lines: [] };
      blocks.push(currentTop);
      continue;
    }
    if (currentTop) currentTop.lines.push(line);
  }

